'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { getSubjectsAction, addSubjectAction, updateSubjectAction, deleteSubjectAction } from '@/app/actions/dbActions';
import { Subject } from '@/utils/storage';
import { Book, Plus, Trash2, Calendar, Loader2, AlertTriangle } from 'lucide-react';
import { toast } from 'sonner';

const DAYS = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

export default function ManageSubjects() {
  const { user } = useAuth();
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [newSubjectName, setNewSubjectName] = useState('');
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (user?.id) {
      loadSubjects();
    }
  }, [user]);

  const loadSubjects = async () => {
    setLoading(true);
    setError(null);
    try {
      if (user?.id) {
        const allSubjects = await getSubjectsAction();
        const teacherSubjects = allSubjects.filter(s => s.teacherId === user.id);
        setSubjects(teacherSubjects);
      }
    } catch (err: any) {
      setError('Failed to load subjects. Please try again.');
      toast.error('Failed to load subjects.');
    } finally {
      setLoading(false);
    }
  };

  const addSubject = async () => {
    if (!newSubjectName.trim() || !user?.id) return;

    try {
      const newSubject = {
        id: `SUB-${Date.now()}`,
        name: newSubjectName.trim(),
        teacherId: user.id,
        teacherName: user.name,
        day: 'Mon',
        startTime: '08:00',
        dismissalTime: '09:00',
      };
      await addSubjectAction(newSubject);
      setSubjects([...subjects, newSubject]);
      setNewSubjectName('');
      toast.success("Subject added!");
    } catch (err) {
      setError('Failed to add subject.');
      toast.error('Failed to add subject.');
    }
  };

  const deleteSubject = async (subject: Subject) => {
    if (!window.confirm(`Delete subject "${subject.name}"?`)) return;

    try {
      await deleteSubjectAction(subject.id);
      setSubjects(subjects.filter((s) => s.id !== subject.id));
      if (selectedSubject?.id === subject.id) {
        setSelectedSubject(null);
      }
      toast.success("Subject deleted.");
    } catch (err) {
      setError('Failed to delete subject.');
      toast.error('Failed to delete subject.');
    }
  };

  const updateSubjectSchedules = async (subject: Subject, schedules: any[]) => {
    try {
      const updatedSubject = { ...subject, schedules: schedules };
      await updateSubjectAction(updatedSubject);
      const updatedSubjects = subjects.map((s) => (s.id === subject.id ? updatedSubject : s));
      setSubjects(updatedSubjects);
      setSelectedSubject(updatedSubject);
      toast.success("Schedule updated.");
    } catch (err) {
      setError('Failed to update schedules.');
      toast.error('Failed to update schedules.');
    }
  };
  
  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <Loader2 className="animate-spin text-[#b40000]" size={48} />
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg flex items-center">
        <AlertTriangle className="mr-2" />
        <span>{error}</span>
        <button onClick={loadSubjects} className="ml-auto px-3 py-1 bg-red-600 text-white rounded">Retry</button>
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-3xl mb-2">Manage Subjects</h2>
      <p className="text-gray-600 mb-8">Add subjects and set their schedules</p>

      <div className="grid md:grid-cols-2 gap-8">
        <div className="bg-white rounded-xl shadow-lg p-6">
          <h3 className="text-xl mb-4 flex items-center gap-2">
            <Book className="text-[#b40000]" />
            Subjects
          </h3>

          <div className="flex gap-2 mb-6">
            <input
              type="text"
              value={newSubjectName}
              onChange={(e) => setNewSubjectName(e.target.value)}
              placeholder="New subject name..."
              className="flex-1 px-4 py-2 border rounded-lg"
              onKeyPress={(e) => e.key === 'Enter' && addSubject()}
            />
            <button
              onClick={addSubject}
              className="px-4 py-2 bg-[#b40000] text-white rounded-lg hover:bg-[#8b0000] disabled:bg-gray-400"
              disabled={!newSubjectName.trim()}
            >
              <Plus size={20} />
            </button>
          </div>

          <div className="space-y-2">
            {subjects.map((subject) => (
              <div
                key={subject.id}
                className={`p-4 rounded-lg cursor-pointer flex items-center justify-between ${
                  selectedSubject?.id === subject.id
                    ? 'bg-red-50 border-2 border-[#b40000]'
                    : 'bg-gray-50 hover:bg-gray-100'
                }`}
                onClick={() => setSelectedSubject(subject)}
              >
                <span>{subject.name}</span>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    deleteSubject(subject);
                  }}
                  className="p-2 text-red-600 hover:bg-red-100 rounded"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-lg p-6">
          {selectedSubject ? (
            <>
              <h3 className="text-xl mb-4 flex items-center gap-2">
                <Calendar className="text-[#b40000]" />
                Schedule for {selectedSubject.name}
              </h3>
              {/* Simplified schedule management */}
              <p className="text-gray-500">Edit schedule details in the "Edit Subject" dialog.</p>
            </>
          ) : (
            <div className="text-center py-12 text-gray-500">
              Select a subject to manage schedules
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
