
'use client';

import React, { useState, useEffect } from 'react';
import Layout from '../shared/Layout';
import { useAuth } from '../../contexts/AuthContext';
import { Book, Users } from 'lucide-react';
import PendingRequests from './PendingRequests';
import PendingEnrollments from './PendingEnrollments';
import EnrolledStudents from './EnrolledStudents';
import ManageSubjects from './ManageSubjects';
import LabView from './LabView';
import RoomReservations from './RoomReservations';
import AttendanceRecords from './AttendanceRecords';
import { getSubjectsAction, getEnrollmentsAction } from '@/app/actions/dbActions';

export default function TeacherDashboard() {
  const { user } = useAuth();
  const [currentView, setCurrentView] = useState('home');
  const [subjects, setSubjects] = useState<any[]>([]);

  useEffect(() => {
    if (currentView === 'home' && user) {
      loadSubjects();
    }
  }, [currentView, user]);

  const loadSubjects = async () => {
    if (!user?.id) return;
    try {
      const data = await getSubjectsAction();
      const teacherSubjects = data.filter(s => s.teacherId === user.id);
      setSubjects(teacherSubjects);
    } catch (error) {
      console.error("Error fetching subjects:", error);
      setSubjects([]);
    }
  };

  const showSubjectStudents = async (subjectName: string) => {
    const enrollments = await getEnrollmentsAction();
    
    const approved = enrollments.filter(
      (e: any) => e.teacher === user?.id && e.subject === subjectName && e.status === 'Approved'
    );

    let message = `Subject: ${subjectName}\n\nEnrolled Students:\n\n`;
    
    if (approved.length === 0) {
      message += 'No enrolled students yet.';
    } else {
      approved.forEach((enrollment: any, idx: number) => {
        message += `${idx + 1}. ${enrollment.student_name} (${enrollment.studentId})\n`;
      });
    }

    alert(message);
  };

  const renderHome = () => (
    <div>
      <h2 className="text-3xl mb-2">Welcome, {user?.name}</h2>
      <p className="text-gray-600 text-lg mb-8">Your Subjects</p>

      <div className="bg-white rounded-xl shadow-lg p-8">
        <h3 className="text-2xl mb-6 flex items-center gap-2">
          <Book className="text-[#b40000]" />
          Click a subject to view enrolled students
        </h3>

        {subjects.length === 0 ? (
          <div className="text-center py-12 text-gray-500">
            <Book size={64} className="mx-auto mb-4 opacity-50" />
            <p className="text-lg mb-4">Wala pang subjects.</p>
            <button
              onClick={() => setCurrentView('manage-subjects')}
              className="px-6 py-3 bg-[#b40000] text-white rounded-lg hover:bg-[#8b0000] transition-colors"
            >
              Manage Subjects
            </button>
          </div>
        ) : (
          <div className="grid gap-4">
            {subjects.map((subject, idx) => (
              <button
                key={idx}
                onClick={() => showSubjectStudents(subject.name)}
                className="p-6 bg-gray-50 hover:bg-gray-100 rounded-lg text-left transition-colors border border-gray-200 hover:border-[#b40000]"
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <Book size={24} className="text-[#b40000]" />
                    <span className="text-lg">{subject.name}</span>
                  </div>
                  <Users size={20} className="text-gray-400" />
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case 'home':
        return renderHome();
      case 'pending-requests':
        return <PendingRequests />;
      case 'pending-enrollments':
        return <PendingEnrollments />;
      case 'enrolled-students':
        return <EnrolledStudents />;
      case 'lab-view':
        return <LabView />;
      case 'manage-subjects':
        return <ManageSubjects />;
      case 'reservations':
        return <RoomReservations />;
      case 'attendance-records':
        return <AttendanceRecords />;
      default:
        return renderHome();
    }
  };

  return (
    <Layout currentView={currentView} onNavigate={setCurrentView}>
      {renderContent()}
    </Layout>
  );
}
