
'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { FileText, Send, AlertCircle } from 'lucide-react';
import { getEnrollmentsAction, getUsersAction, getSubjectsAction, getLabsAction, getRoomsAction, getPcsAction } from '@/app/actions/dbActions';

export default function MakeRequest() {
  const { user } = useAuth();
  const [teachers, setTeachers] = useState<any[]>([]);
  const [subjects, setSubjects] = useState<any[]>([]);
  const [labs, setLabs] = useState<any[]>([]);
  const [rooms, setRooms] = useState<any[]>([]);
  const [availablePCs, setAvailablePCs] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    teacher: '',
    subject: '',
    type: 'lab',
    labOrRoom: '',
    pc: '',
    startTime: '',
    endTime: '',
    reason: ''
  });
  const [error, setError] = useState('');

  useEffect(() => {
    if(user) {
      loadInitialData();
    }
  }, [user]);

  useEffect(() => {
    if (formData.teacher) {
      loadSubjectsForTeacher(formData.teacher);
    }
  }, [formData.teacher]);

  useEffect(() => {
    if (formData.type === 'lab' && formData.labOrRoom) {
      loadAvailablePCs(formData.labOrRoom);
    }
  }, [formData.labOrRoom, formData.type]);

  const loadInitialData = async () => {
    const enrollments = await getEnrollmentsAction();
    const allUsers = await getUsersAction();
    const myApproved = enrollments.filter(
      (e: any) => e.studentId === user?.id && e.status === 'approved'
    );
    const teacherIds = [...new Set(myApproved.map((e:any) => e.subjectId).map((sId:string) => {
        const subjects = JSON.parse(localStorage.getItem('subjects') || '[]');
        return subjects.find((s:any) => s.id === sId)?.teacherId
    }))];

    const uniqueTeachers = allUsers.filter(u => teacherIds.includes(u.id));

    setTeachers(uniqueTeachers);
    setLabs(await getLabsAction());
    setRooms(await getRoomsAction());
  };

  const loadSubjectsForTeacher = async (teacherId: string) => {
    const enrollments = await getEnrollmentsAction();
    const allSubjects = await getSubjectsAction();
    const mySubjectsForTeacher = enrollments
      .filter((e: any) => e.studentId === user?.id && e.status === 'approved')
      .map((e:any) => allSubjects.find(s => s.id === e.subjectId))
      .filter(s => s && s.teacherId === teacherId);

    setSubjects(mySubjectsForTeacher);
  };

  const loadAvailablePCs = async (labId: string) => {
    const allPcs = await getPcsAction();
    const available = allPcs.filter(pc => pc.labId === labId && pc.status === 'available');
    setAvailablePCs(available);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!formData.teacher || !formData.subject) {
      setError('Please select teacher and subject');
      return;
    }

    if (formData.type === 'lab' && !formData.pc) {
      setError('Please select a PC');
      return;
    }

    if (formData.type === 'room' && !formData.labOrRoom) {
      setError('Please select a room');
      return;
    }

    if (!formData.startTime || !formData.endTime) {
      setError('Please enter start and end time');
      return;
    }

    console.log({formData})
    alert('Request submitted successfully! (Not really, this is a mock)');
    
    // Reset form
    setFormData({
        teacher: '',
        subject: '',
        type: 'lab',
        labOrRoom: '',
        pc: '',
        startTime: '',
        endTime: '',
        reason: ''
    });
  };

  return (
    <div className="max-w-4xl">
      <h2 className="text-3xl mb-2">Make Lab Request</h2>
      <p className="text-gray-600 mb-8">Request access to lab or room</p>

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6 flex items-center gap-2">
          <AlertCircle size={20} />
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-lg p-8 space-y-6">
        <div className="grid md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm mb-2 text-gray-700">Teacher</label>
            <select
              value={formData.teacher}
              onChange={(e) => setFormData({ ...formData, teacher: e.target.value, subject: '' })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              required
            >
              <option value="">Select Teacher</option>
              {teachers.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm mb-2 text-gray-700">Subject</label>
            <select
              value={formData.subject}
              onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              required
              disabled={!formData.teacher}
            >
              <option value="">Select Subject</option>
              {subjects.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <label className="block text-sm mb-2 text-gray-700">Request Type</label>
          <div className="flex gap-4">
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                value="lab"
                checked={formData.type === 'lab'}
                onChange={(e) => setFormData({ ...formData, type: e.target.value, labOrRoom: '', pc: ''})}
                className="w-4 h-4 text-[#b40000]"
              />
              <span>Lab (with PC)</span>
            </label>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                value="room"
                checked={formData.type === 'room'}
                onChange={(e) => setFormData({ ...formData, type: e.target.value, labOrRoom: '', pc: ''})}
                className="w-4 h-4 text-[#b40000]"
              />
              <span>Room</span>
            </label>
          </div>
        </div>

        {formData.type === 'lab' ? (
          <>
            <div>
              <label className="block text-sm mb-2 text-gray-700">Lab</label>
              <select
                value={formData.labOrRoom}
                onChange={(e) => setFormData({ ...formData, labOrRoom: e.target.value, pc: '' })}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
                required
              >
                <option value="">Select Lab</option>
                {labs.map((lab) => (
                  <option key={lab.id} value={lab.id}>
                    {lab.name} (Capacity: {lab.capacity})
                  </option>
                ))}
              </select>
            </div>

            {formData.labOrRoom && (
              <div>
                <label className="block text-sm mb-2 text-gray-700">
                  Available PCs ({availablePCs.length} available)
                </label>
                <select
                  value={formData.pc}
                  onChange={(e) => setFormData({ ...formData, pc: e.target.value })}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
                  required
                >
                  <option value="">Select PC</option>
                  {availablePCs.map((pc) => (
                    <option key={pc.id} value={pc.id}>
                      PC {pc.pcNumber}
                    </option>
                  ))}
                </select>
              </div>
            )}
          </>
        ) : (
          <div>
            <label className="block text-sm mb-2 text-gray-700">Room</label>
            <select
              value={formData.labOrRoom}
              onChange={(e) => setFormData({ ...formData, labOrRoom: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              required
            >
              <option value="">Select Room</option>
              {rooms.map((room) => (
                <option key={room.id} value={room.id}>
                  {room.name} (Capacity: {room.capacity})
                </option>
              ))}
            </select>
          </div>
        )}

        <div className="grid md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm mb-2 text-gray-700">Start Time</label>
            <input
              type="time"
              value={formData.startTime}
              onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              required
            />
          </div>

          <div>
            <label className="block text-sm mb-2 text-gray-700">End Time</label>
            <input
              type="time"
              value={formData.endTime}
              onChange={(e) => setFormData({ ...formData, endTime: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              required
            />
          </div>
        </div>

        {(formData.teacher === 'admin' && formData.subject === 'Personal Use') && (
          <div>
            <label className="block text-sm mb-2 text-gray-700">Reason (Required for Personal Use)</label>
            <textarea
              value={formData.reason}
              onChange={(e) => setFormData({ ...formData, reason: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#b40000] focus:border-transparent outline-none"
              rows={4}
              required
            />
          </div>
        )}

        <button
          type="submit"
          className="w-full bg-[#b40000] hover:bg-[#8b0000] text-white py-3 rounded-lg transition-colors flex items-center justify-center gap-2"
        >
          <Send size={20} />
          Submit Request
        </button>
      </form>
    </div>
  );
}
